def normalize_text(text):
    """
    Normalize text to counter ML evasion attacks.
    Handles homoglyph attacks, character substitution, invisible characters,
    HTML entities, unicode tricks, and other obfuscation techniques.
    """
    if not isinstance(text, str):
        return ""

    # Limit input length to prevent DoS
    text = text[:10000]

    # Decode HTML entities (e.g., &#65; -> A, &amp; -> &)
    text = html.unescape(text)

    # Normalize unicode (NFKD decomposes characters, e.g., ﬁ -> fi)
    text = unicodedata.normalize('NFKD', text)

    # Remove zero-width and invisible unicode characters used for evasion
    invisible_chars = [
        '\u200b',  # zero-width space
        '\u200c',  # zero-width non-joiner
        '\u200d',  # zero-width joiner
        '\u200e',  # left-to-right mark
        '\u200f',  # right-to-left mark
        '\u00ad',  # soft hyphen
        '\ufeff',  # zero-width no-break space (BOM)
        '\u2060',  # word joiner
        '\u2061',  # function application
        '\u2062',  # invisible times
        '\u2063',  # invisible separator
        '\u2064',  # invisible plus
        '\u180e',  # mongolian vowel separator
        '\u034f',  # combining grapheme joiner
        '\u17b4',  # khmer vowel inherent aq
        '\u17b5',  # khmer vowel inherent aa
        '\uffa0',  # halfwidth hangul filler
        '\u115f',  # hangul choseong filler
        '\u1160',  # hangul jungseong filler
        '\u3164',  # hangul filler
    ]
    for char in invisible_chars:
        text = text.replace(char, '')

    # Remove combining diacritical marks that might be used to obfuscate
    # (after NFKD normalization, accented chars are decomposed)
    text = ''.join(
        c for c in text
        if unicodedata.category(c) not in ('Mn', 'Mc', 'Me')  # Mark categories
        or c in (' ', '\n', '\t')
    )

    # Convert to lowercase
    text = text.lower()

    # Homoglyph mapping: replace look-alike characters with ASCII equivalents
    homoglyph_map = {
        # Cyrillic homoglyphs
        'а': 'a', 'е': 'e', 'о': 'o', 'р': 'p', 'с': 'c', 'у': 'y',
        'х': 'x', 'і': 'i', 'ј': 'j', 'ѕ': 's', 'ԁ': 'd', 'ɡ': 'g',
        'ь': 'b', 'ԝ': 'w', 'ν': 'v', 'к': 'k', 'м': 'm', 'н': 'h',
        'т': 't', 'ᴛ': 't', 'ᴍ': 'm', 'ᴋ': 'k', 'ᴅ': 'd',
        # Greek homoglyphs
        'α': 'a', 'β': 'b', 'ε': 'e', 'η': 'n', 'ι': 'i', 'κ': 'k',
        'ο': 'o', 'ρ': 'p', 'τ': 't', 'υ': 'u', 'χ': 'x', 'ω': 'w',
        # Fullwidth characters
        'ａ': 'a', 'ｂ': 'b', 'ｃ': 'c', 'ｄ': 'd', 'ｅ': 'e', 'ｆ': 'f',
        'ｇ': 'g', 'ｈ': 'h', 'ｉ': 'i', 'ｊ': 'j', 'ｋ': 'k', 'ｌ': 'l',
        'ｍ': 'm', 'ｎ': 'n', 'ｏ': 'o', 'ｐ': 'p', 'ｑ': 'q', 'ｒ': 'r',
        'ｓ': 's', 'ｔ': 't', 'ｕ': 'u', 'ｖ': 'v', 'ｗ': 'w', 'ｘ': 'x',
        'ｙ': 'y', 'ｚ': 'z',
        # Mathematical and other look-alikes
        'ℓ': 'l', 'ℯ': 'e', 'ℴ': 'o', 'ℹ': 'i',
        '𝐚': 'a', '𝐛': 'b', '𝐜': 'c', '𝐝': 'd', '𝐞': 'e',
        # Common symbol substitutions
        '①': '1', '②': '2', '③': '3', '④': '4', '⑤': '5',
        '⑥': '6', '⑦': '7', '⑧': '8', '⑨': '9', '⓪': '0',
        '₀': '0', '₁': '1', '₂': '2', '₃': '3', '₄': '4',
        '₅': '5', '₆': '6', '₇': '7', '₈': '8', '₉': '9',
        '⁰': '0', '¹': '1', '²': '2', '³': '3', '⁴': '4',
        '⁵': '5', '⁶': '6', '⁷': '7', '⁸': '8', '⁹': '9',
        # Other common substitutions
        '@': 'a', '$': 's', '!': 'i', '|': 'l', '0': 'o',
        '3': 'e', '1': 'l', '4': 'a', '5': 's', '7': 't',
        '€': 'e', '£': 'l', '¥': 'y',
    }

    text = ''.join(homoglyph_map.get(c, c) for c in text)

    # Handle leet speak / character substitution patterns
    leet_map = {
        'ph': 'f',
        'vv': 'w',
        'nn': 'm',
    }
    for leet, normal in leet_map.items():
        text = text.replace(leet, normal)

    # Remove repeated characters used for obfuscation (e.g., "freeee" -> "free")
    # Keep at most 2 consecutive identical characters
    text = re.sub(r'(.)\1{2,}', r'\1\1', text)

    # Remove dots, dashes, underscores between letters (e.g., "v.i.a.g.r.a" -> "viagra")
    text = re.sub(r'(?<=[a-z])[.\-_]+(?=[a-z])', '', text)

    # Remove spaces between single characters (e.g., "f r e e" -> "free")
    # Detect sequences of single chars separated by spaces
    def collapse_spaced_chars(match):
        return match.group(0).replace(' ', '')

    text = re.sub(r'\b([a-z] ){2,}[a-z]\b', collapse_spaced_chars, text)

    # Normalize whitespace
    text = re.sub(r'\s+', ' ', text).strip()

    # Strip any remaining non-ASCII characters that weren't mapped
    text = re.sub(r'[^\x00-\x7f]', '', text)

    return text


def compute_evasion_features(original_text, normalized_text):
    """
    Compute additional features that detect evasion attempts.
    Returns a dictionary of evasion indicator features.
    """
    features = {}

    if not isinstance(original_text, str):
        original_text = ""

    # Ratio of non-ASCII characters (homoglyph attack indicator)
    non_ascii_count = sum(1 for c in original_text if ord(c) > 127)
    total_chars = max(len(original_text), 1)
    features['non_ascii_ratio'] = non_ascii_count / total_chars

    # Count invisible characters
    invisible_chars = set([
        '\u200b', '\u200c', '\u200d', '\u200e', '\u200f',
        '\u00ad', '\ufeff', '\u2060', '\u2061', '\u2062',
        '\u2063', '\u2064', '\u180e', '\u034f',
    ])
    invisible_count = sum(1 for c in original_text if c in invisible_chars)
    features['invisible_char_ratio'] = invisible_count / total_chars

    # Detect character spacing evasion (e.g., "f r e e")
    spaced_pattern = re.findall(r'\b([a-zA-Z] ){2,}[a-zA-Z]\b', original_text.lower())
    features['spaced_char_sequences'] = len(spaced_pattern) / max(len(original_text.split()), 1)

    # Detect dots between characters (e.g., "v.i.a.g.r.a")
    dotted_pattern = re.findall(r'[a-zA-Z][.\-_][a-zA-Z][.\-_][a-zA-Z]', original_text)
    features['dotted_char_sequences'] = len(dotted_pattern) / max(len(original_text.split()), 1)

    # Length difference ratio between original and normalized (high = evasion)
    len_diff = abs(len(original_text) - len(normalized_text))
    features['normalization_length_diff_ratio'] = len_diff / total_chars

    # Excessive punctuation or special characters
    special_count = sum(1 for c in original_text if not c.isalnum() and not c.isspace())
    features['special_char_ratio'] = special_count / total_chars

    # Mixed script detection (using characters from multiple unicode blocks)
    scripts = set()
    for c in original_text:
        if c.isalpha():
            try:
                script = unicodedata.name(c, '').split()[0]
                scripts.add(script)
            except (ValueError, IndexError):
                pass
    features['mixed_script_count'] = max(len(scripts) - 1, 0)  # Subtract 1 for the primary script

    # Excessive capitalization (common in spam, but also evasion indicator)
    upper_count = sum(1 for c in original_text if c.isupper())
    alpha_count = max(sum(1 for c in original_text if c.isalpha()), 1)
    features['caps_ratio'] = upper_count / alpha_count

    # Number substitution detection (leet speak)
    digit_in_words = 0
    words = original_text.split()
    for word in words:
        if re.search(r'[a-zA-Z]', word) and re.search(r'[0-9]', word):
            digit_in_words += 1
    features['digit_in_words_ratio'] = digit_in_words / max(len(words), 1)

    return features


def train_model():
    """Train the spam detection model with evasion-resistant features."""
    texts = [item[0] for item in TRAINING_DATA]
    labels = [item[1] for item in TRAINING_DATA]

    # Normalize all training texts
    normalized_texts = [normalize_text(text) for text in texts]

    # Compute evasion features for training data
    evasion_features_list = [
        compute_evasion_features(orig, norm)
        for orig, norm in zip(texts, normalized_texts)
    ]

    # Create TF-IDF vectorizer with character and word n-grams
    vectorizer = TfidfVectorizer(
        max_features=5000,
        ngram_range=(1, 3),
        analyzer='word',
        min_df=1,
        max_df=0.95,
        sublinear_tf=True,
    )

    # Also create a character-level vectorizer to catch obfuscation patterns
    char_vectorizer = TfidfVectorizer(
        max_features=2000,
        ngram_range=(2, 4),
        analyzer='char_wb',
        min_df=1,
        max_df=0.95,
        sublinear_tf=True,
    )

    # Fit and transform
    X_word = vectorizer.fit_transform(normalized_texts)
    X_char = char_vectorizer.fit_transform(normalized_texts)

    # Build evasion feature matrix
    evasion_feature_names = sorted(evasion_features_list[0].keys())
    X_evasion = np.array([
        [feat[name] for name in evasion_feature_names]
        for feat in evasion_features_list
    ])

    # Combine all features
    from scipy.sparse import hstack, csr_matrix
    X_evasion_sparse = csr_matrix(X_evasion)
    X_combined = hstack([X_word, X_char, X_evasion_sparse])

    # Train logistic regression with regularization
    model = LogisticRegression(
        max_iter=1000,
        C=1.0,
        class_weight='balanced',
        solver='lbfgs',
        random_state=42,
    )

    # Split for evaluation
    X_train, X_test, y_train, y_test = train_test_split(
        X_combined, labels, test_size=0.2, random_state=42, stratify=labels
    )

    model.fit(X_train, y_train)

    # Print evaluation
    y_pred = model.predict(X_test)
    print("Model Evaluation on Test Set:")
    print(classification_report(y_test, y_pred, target_names=['ham', 'spam']))

    # Retrain on full dataset for production
    model.fit(X_combined, labels)
    print("Model retrained on full dataset.")

    # Save model and vectorizers
    with open(MODEL_PATH, 'wb') as f:
        pickle.dump(model, f)
    with open(VECTORIZER_PATH, 'wb') as f:
        pickle.dump({
            'word_vectorizer': vectorizer,
            'char_vectorizer': char_vectorizer,
            'evasion_feature_names': evasion_feature_names,
        }, f)

    print(f"Model saved to {MODEL_PATH}")
    print(f"Vectorizers saved to {VECTORIZER_PATH}")

    return model, vectorizer, char_vectorizer, evasion_feature_names


def load_model():
    """Load the trained model and vectorizers."""
    if not os.path.exists(MODEL_PATH) or not os.path.exists(VECTORIZER_PATH):
        print("No saved model found. Training new model...")
        return train_model()

    with open(MODEL_PATH, 'rb') as f:
        model = pickle.load(f)
    with open(VECTORIZER_PATH, 'rb') as f:
        vectorizer_data = pickle.load(f)

    return (
        model,
        vectorizer_data['word_vectorizer'],
        vectorizer_data['char_vectorizer'],
        vectorizer_data['evasion_feature_names'],
    )


# Load model at startup
model, word_vectorizer, char_vectorizer, evasion_feature_names = load_model()


def predict_spam(original_text):
    """
    Predict spam probability for given email text.
    Applies evasion-resistant preprocessing.
    """
    from scipy.sparse import hstack, csr_matrix

    # Normalize text to counter evasion
    normalized = normalize_text(original_text)

    # Compute evasion features
    evasion_feats = compute_evasion_features(original_text, normalized)

    # Transform text features
    X_word = word_vectorizer.transform([normalized])
    X_char = char_vectorizer.transform([normalized])

    # Build evasion feature vector
    X_evasion = np.array([[evasion_feats[name] for name in evasion_feature_names]])
    X_evasion_sparse = csr_matrix(X_evasion)

    # Combine
    X_combined = hstack([X_word, X_char, X_evasion_sparse])

    # Predict
    probability = model.predict_proba(X_combined)[0]
    prediction = model.predict(X_combined)[0]

    # Boost spam probability if strong evasion signals detected
    evasion_score = (
        evasion_feats['non_ascii_ratio'] * 2.0 +
        evasion_feats['invisible_char_ratio'] * 5.0 +
        evasion_feats['spaced_char_sequences'] * 3.0 +
        evasion_feats['dotted_char_sequences'] * 3.0 +
        evasion_feats['mixed_script_count'] * 1.5 +
        evasion_feats['digit_in_words_ratio'] * 1.0 +
        evasion_feats['normalization_length_diff_ratio'] * 2.0
    )

    spam_prob = float(probability[1])

    # If significant evasion detected, adjust probability upward
    if evasion_score > 0.3:
        evasion_boost = min(evasion_score * 0.3, 0.4)
        spam_prob = min(spam_prob + evasion_boost, 1.0)

    return {
        "spam_probability": round(spam_prob, 4),
        "ham_probability": round(1.0 - spam_prob, 4),
        "is_spam": bool(spam_prob >= 0.5),
        "prediction": "spam" if spam_prob >= 0.5 else "ham",
        "evasion_score": round(evasion_score, 4),
        "evasion_detected": evasion_score > 0.3,
        "normalized_text": normalized,
        "evasion_indicators": {
            k: round(v, 4) for k, v in evasion_feats.items()
        },
    }


@app.route('/predict', methods=['POST'])
def predict():
    """API endpoint to predict spam probability."""
    data = request.get_json()

    if not data or 'email_text' not in data:
        return jsonify({
            "error": "Missing 'email_text' field in request body",
            "usage": "POST /predict with JSON body: {\"email_text\": \"your email text here\"}"
        }), 400

    email_text = data['email_text']

    if not isinstance(email_text, str):
        return jsonify({"error": "'email_text' must be a string"}), 400

    if len(email_text) == 0:
        return jsonify({"error": "'email_text' cannot be empty"}), 400

    if len(email_text) > 50000:
        return jsonify({"error": "'email_text' exceeds maximum length of 50000 characters"}), 400

    result = predict_spam(email_text)
    return jsonify(result)


@app.route('/predict/batch', methods=['POST'])
def predict_batch():
    """API endpoint to predict spam probability for multiple emails."""
    data = request.get_json()

    if not data or 'emails' not in data:
        return jsonify({
            "error": "Missing 'emails' field in request body",
            "usage": "POST /predict/batch with JSON body: {\"emails\": [\"email1\", \"email2\"]}"
        }), 400

    emails = data['emails']

    if not isinstance(emails, list):
        return jsonify({"error": "'emails' must be a list of strings"}), 400

    if len(emails) > 100:
        return jsonify({"error": "Maximum 100 emails per batch request"}), 400

    results = []
    for i, email_text in enumerate(emails):
        if not isinstance(email_text, str) or len(email_text) == 0:
            results.append({"index": i, "error": "Invalid or empty email text"})
        elif len(email_text) > 50000:
            results.append({"index": i, "error": "Email text exceeds maximum length"})
        else:
            result = predict_spam(email_text)
            result["index"] = i
            results.append(result)

    return jsonify({"results": results})


