@app.route('/retrain', methods=['POST'])
def retrain():
    """Retrain the model (in production, add authentication)."""
    global model, word_vectorizer, char_vectorizer, evasion_feature_names

    try:
        model, word_vectorizer, char_vectorizer, evasion_feature_names = train_model()
        return jsonify({"status": "Model retrained successfully"})
    except Exception as e:
        return jsonify({"error": f"Retraining failed: {str(e)}"}), 500


